test.config:
indexer
{
	mem_limit = 16M
}

searchd
{

	binlog_path =
}

source src_ok
{
	type = xmlpipe2
	xmlpipe_command = cat /data.xml
	xmlpipe_field = title
}

index ok_idx
{
	source = src_ok
	path = /ok_idx
}

test.custom_test:
$results = array();
$orig_conf = implode ( '', file ( testdir_config() ) );

global $index_data_path;
$runInvalidIndexer = function ( $name, $extraBlock, $target ) use ( &$results, $orig_conf )
{
	file_put_contents ( testdir_config(), $orig_conf . "\n" . $extraBlock . "\n" );
	$error = '';
	$ret = RunIndexer ( $error, $target );
	$results[] = $name;
	$results[] = "ret=$ret";
	$results[] = trim ( $error );
	file_put_contents ( testdir_config(), $orig_conf );
};

$runInvalidIndexer (
	'invalid ranker in config',
	"index bad_ranker\n{\n\tsource = src_ok\n\tpath = $index_data_path/bad_ranker\n\tranker = typo\n}\n",
	'bad_ranker'
);

$runInvalidIndexer (
	'invalid uppercase boolean_mode in config',
	"index bad_boolean_upper\n{\n\tsource = src_ok\n\tpath = $index_data_path/bad_boolean_upper\n\tboolean_mode = OR\n}\n",
	'bad_boolean_upper'
);

$runInvalidIndexer (
	'invalid typo boolean_mode in config',
	"index bad_boolean_typo\n{\n\tsource = src_ok\n\tpath = $index_data_path/bad_boolean_typo\n\tboolean_mode = typo\n}\n",
	'bad_boolean_typo'
);

$runInvalidIndexer (
	'invalid schema ranker expression in config',
	"index bad_ranker_expr\n{\n\tsource = src_ok\n\tpath = $index_data_path/bad_ranker_expr\n\tranker = expr('sum(missing_score)')\n}\n",
	'bad_ranker_expr'
);
